/*
  # Seed Govern sidebar groups and pages

  Creates 6 sidebar groups with ~35 child topic pages for the
  Govern section. Organized by governance function: constitution,
  RFC process, working groups, shared segments, federal compliance,
  and Foundation governance.
*/

DO $$
DECLARE
  v_section_id uuid;
  v_group_id uuid;
BEGIN
  SELECT id INTO v_section_id FROM nav_sections WHERE slug = 'govern';

  -- Group 1: The Constitution
  VALUES (v_section_id, 'The Constitution', 'the-constitution', 1)
  RETURNING id INTO v_group_id;


  -- Group 2: The RFC Process
  VALUES (v_section_id, 'The RFC Process', 'the-rfc-process', 2)
  RETURNING id INTO v_group_id;


  -- Group 3: Working Groups
  VALUES (v_section_id, 'Working Groups', 'working-groups', 3)
  RETURNING id INTO v_group_id;


  -- Group 4: The Shared Segment Commons
  VALUES (v_section_id, 'The Shared Segment Commons', 'the-shared-segment-commons', 4)
  RETURNING id INTO v_group_id;


  -- Group 5: Federal Compliance Alignment
  VALUES (v_section_id, 'Federal Compliance Alignment', 'federal-compliance-alignment', 5)
  RETURNING id INTO v_group_id;


  -- Group 6: Foundation Governance
  VALUES (v_section_id, 'Foundation Governance', 'foundation-governance', 6)
  RETURNING id INTO v_group_id;


END $$;
